3	/**
4	 * Structured error thrown when all credentials for a provider are in a
5	 * backoff window.  Carries typed metadata so callers (e.g. the auto-loop)
6	 * can make informed retry decisions instead of string-matching the message.
7	 */
8	export class CredentialCooldownError extends Error {
9		readonly code = "AUTH_COOLDOWN" as const;
10		/** Milliseconds until the earliest credential becomes available, or undefined if unknown. */
11		readonly retryAfterMs: number | undefined;
12	
13		constructor(provider: string, retryAfterMs?: number) {
14			super(
15				`All credentials for "${provider}" are in a cooldown window. ` +
16					`Please wait a moment and try again, or switch to a different provider.`,
17			);
18			this.name = "CredentialCooldownError";
19			this.retryAfterMs = retryAfterMs;
20		}
21	}
22	import { Agent, type AgentMessage, type ThinkingLevel } from "@gsd/pi-agent-core";
