67	export interface CreateAgentSessionOptions {
68		/** Working directory for project-local discovery. Default: process.cwd() */
69		cwd?: string;
70		/** Global config directory. Default: ~/.pi/agent */
71		agentDir?: string;
72	
73		/** Auth storage for credentials. Default: AuthStorage.create(agentDir/auth.json) */
