94		sessionManager?: SessionManager;
95	
96		/** Settings manager. Default: SettingsManager.create(cwd, agentDir) */
97		settingsManager?: SettingsManager;
98	
99		/** Optional: check if the claude-code CLI provider is ready (installed + authed).
100		 * Passed to RetryHandler for third-party block recovery (#3772). */
101		isClaudeCodeReady?: () => boolean;
102	}
